---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

const SIDEBAR_WIDTH = "16rem"
const SIDEBAR_WIDTH_MOBILE = "18rem"
const SIDEBAR_WIDTH_ICON = "3rem"

type Props = HTMLAttributes<"div"> & {
  defaultOpen?: boolean
  open?: boolean
}

const {
  class: className,
  style,
  defaultOpen = true,
  open,
  ...props
} = Astro.props

const resolvedStyle = [
  `--sidebar-width: ${SIDEBAR_WIDTH}`,
  `--sidebar-width-mobile: ${SIDEBAR_WIDTH_MOBILE}`,
  `--sidebar-width-icon: ${SIDEBAR_WIDTH_ICON}`,
  typeof style === "string" ? style : undefined,
]
  .filter(Boolean)
  .join("; ")
---

<div
  data-slot="sidebar-wrapper"
  data-default-open={defaultOpen ? "true" : "false"}
  data-open={open === undefined ? undefined : open ? "true" : "false"}
  style={resolvedStyle}
  class={cn(
    "group/sidebar-wrapper has-data-[variant=inset]:bg-sidebar flex min-h-svh w-full",
    className
  )}
  {...props}
>
  <slot />
</div>

<script>
  declare global {
    interface Window {
      __fulldevSidebarInitialized?: boolean
    }
  }

  type SidebarProviderElement = HTMLElement
  type SidebarElement = HTMLElement
  type SidebarSheetElement = HTMLElement
  type SidebarRuntimeState = {
    open: boolean
    openMobile: boolean
  }

  const SIDEBAR_COOKIE_NAME = "sidebar_state"
  const SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7
  const SIDEBAR_KEYBOARD_SHORTCUT = "b"
  const DESKTOP_MEDIA_QUERY = "(min-width: 768px)"

  if (!window.__fulldevSidebarInitialized) {
    window.__fulldevSidebarInitialized = true

    const desktopMedia = window.matchMedia(DESKTOP_MEDIA_QUERY)
    const providerState = new WeakMap<
      SidebarProviderElement,
      SidebarRuntimeState
    >()

    const parseBoolean = (value: string | undefined, fallback: boolean) => {
      if (value === "" || value === "true") return true
      if (value === "false") return false
      return fallback
    }

    const getCookie = (name: string) => {
      const cookie = document.cookie
        .split("; ")
        .find((entry) => entry.startsWith(`${name}=`))

      return cookie ? cookie.slice(name.length + 1) : null
    }

    const setCookie = (name: string, value: string, maxAge: number) => {
      document.cookie = `${name}=${value}; path=/; max-age=${maxAge}`
    }

    const isProvider = (
      value: Element | null
    ): value is SidebarProviderElement =>
      value instanceof HTMLElement && value.dataset.slot === "sidebar-wrapper"

    const isDesktopSidebar = (value: Element): value is SidebarElement =>
      value instanceof HTMLElement &&
      value.dataset.slot === "sidebar" &&
      value.dataset.mobile !== "true"

    const isMobileSheet = (value: Element): value is SidebarSheetElement =>
      value instanceof HTMLElement && value.dataset.sidebar === "sheet"

    const getDesktopSidebar = (provider: SidebarProviderElement) => {
      const sidebar = Array.from(
        provider.querySelectorAll<HTMLElement>("[data-slot='sidebar']")
      ).find(isDesktopSidebar)

      return sidebar ?? null
    }

    const getMobileSheet = (provider: SidebarProviderElement) => {
      const sheet = Array.from(
        provider.querySelectorAll<HTMLElement>("[data-sidebar='sheet']")
      ).find(isMobileSheet)

      return sheet ?? null
    }

    const getProviders = (): SidebarProviderElement[] =>
      Array.from(
        document.querySelectorAll<HTMLElement>("[data-slot='sidebar-wrapper']")
      ).filter(isProvider)

    const ensureState = (provider: SidebarProviderElement) => {
      const existingState = providerState.get(provider)
      if (existingState) return existingState

      const nextState: SidebarRuntimeState = {
        open: getSidebarState(provider),
        openMobile: false,
      }

      providerState.set(provider, nextState)
      return nextState
    }

    const getSidebarState = (provider: SidebarProviderElement) => {
      const controlledOpen = provider.dataset.open
      if (controlledOpen === "true" || controlledOpen === "false") {
        return controlledOpen === "true"
      }

      const cookieValue = getCookie(SIDEBAR_COOKIE_NAME)
      if (cookieValue === "true" || cookieValue === "false") {
        return cookieValue === "true"
      }

      return parseBoolean(provider.dataset.defaultOpen, true)
    }

    const hasCollapsibleSidebar = (provider: SidebarProviderElement) =>
      (getDesktopSidebar(provider)?.dataset.sidebarCollapsible ??
        "offcanvas") !== "none" || getMobileSheet(provider) !== null

    const syncProvider = (provider: SidebarProviderElement) => {
      const state = ensureState(provider)
      const desktopSidebar = getDesktopSidebar(provider)
      const collapsible =
        desktopSidebar?.dataset.sidebarCollapsible ?? "offcanvas"

      const desktopState = state.open ? "expanded" : "collapsed"
      provider.dataset.open = state.open ? "true" : "false"
      provider.dataset.openMobile = state.openMobile ? "true" : "false"
      provider.dataset.state = desktopState

      if (desktopSidebar) {
        desktopSidebar.dataset.state =
          collapsible === "none" ? "expanded" : desktopState
        desktopSidebar.dataset.collapsible =
          collapsible === "none" ? "none" : state.open ? "" : collapsible
      }

      provider
        .querySelectorAll("[data-sidebar='trigger'], [data-sidebar='rail']")
        .forEach((control: Element) => {
          if (!(control instanceof HTMLElement)) return

          const isExpanded = desktopMedia.matches
            ? state.open
            : state.openMobile
          control.setAttribute("aria-expanded", String(isExpanded))
        })

      provider
        .querySelectorAll("[data-sidebar='menu-tooltip']")
        .forEach((tooltip: Element) => {
          if (!(tooltip instanceof HTMLElement)) return

          tooltip.hidden = !(
            desktopMedia.matches && desktopState === "collapsed"
          )
        })
    }

    const setMobileOpen = (
      provider: SidebarProviderElement,
      openMobile: boolean,
      { syncSheet = true }: { syncSheet?: boolean } = {}
    ) => {
      const state = ensureState(provider)
      if (state.openMobile === openMobile) return

      state.openMobile = openMobile

      const sheet = getMobileSheet(provider)
      if (syncSheet && sheet) {
        sheet.dispatchEvent(
          new CustomEvent("dialog:set", {
            detail: { open: openMobile },
          })
        )
      }

      syncProvider(provider)
    }

    const setDesktopOpen = (
      provider: SidebarProviderElement,
      openValue: boolean,
      { writeCookie = true }: { writeCookie?: boolean } = {}
    ) => {
      const state = ensureState(provider)
      if (state.open === openValue) return

      state.open = openValue

      if (writeCookie) {
        setCookie(
          SIDEBAR_COOKIE_NAME,
          openValue ? "true" : "false",
          SIDEBAR_COOKIE_MAX_AGE
        )
      }

      syncProvider(provider)
    }

    const toggleProvider = (provider: SidebarProviderElement) => {
      const state = ensureState(provider)
      if (!hasCollapsibleSidebar(provider)) return

      if (desktopMedia.matches) {
        setDesktopOpen(provider, !state.open)
      } else {
        setMobileOpen(provider, !state.openMobile)
      }
    }

    const initProvider = (provider: SidebarProviderElement) => {
      if (provider.dataset.sidebarInitialized === "true") return
      provider.dataset.sidebarInitialized = "true"

      ensureState(provider)

      const sheet = getMobileSheet(provider)
      if (sheet) {
        sheet.addEventListener("dialog:change", (event: Event) => {
          const nextOpen = (
            event as CustomEvent<{ open?: boolean }>
          ).detail?.open
          if (typeof nextOpen !== "boolean") return

          setMobileOpen(provider, nextOpen, { syncSheet: false })
        })
      }

      syncProvider(provider)
    }

    const initAllProviders = () => {
      getProviders().forEach(initProvider)
    }

    const getActiveProvider = (): SidebarProviderElement | null => {
      const activeElement = document.activeElement

      if (activeElement instanceof HTMLElement) {
        const activeProvider = activeElement.closest(
          "[data-slot='sidebar-wrapper']"
        )
        if (isProvider(activeProvider)) return activeProvider
      }

      const firstProvider = document.querySelector<HTMLElement>(
        "[data-slot='sidebar-wrapper']"
      )
      return isProvider(firstProvider) ? firstProvider : null
    }

    document.addEventListener("click", (event) => {
      const target = event.target

      if (!(target instanceof Element)) return

      const control = target.closest(
        "[data-sidebar='trigger'], [data-sidebar='rail']"
      )

      if (!(control instanceof HTMLElement)) return
      if (control.matches(":disabled, [aria-disabled='true']")) return

      const provider = control.closest("[data-slot='sidebar-wrapper']")
      if (!isProvider(provider)) return

      toggleProvider(provider)
    })

    document.addEventListener("keydown", (event) => {
      if (
        event.key.toLowerCase() !== SIDEBAR_KEYBOARD_SHORTCUT ||
        (!event.metaKey && !event.ctrlKey)
      ) {
        return
      }

      const provider = getActiveProvider()
      if (!provider) return

      event.preventDefault()
      toggleProvider(provider)
    })

    const syncAllProviders = () => {
      getProviders().forEach((provider) => {
        const state = ensureState(provider)

        if (desktopMedia.matches && state.openMobile) {
          setMobileOpen(provider, false)
          return
        }

        syncProvider(provider)
      })
    }

    desktopMedia.addEventListener("change", syncAllProviders)

    initAllProviders()
    syncAllProviders()

    document.addEventListener("astro:page-load", () => {
      initAllProviders()
      syncAllProviders()
    })
  }
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"

type Props = HTMLAttributes<"div"> & {
  side?: "left" | "right"
  variant?: "sidebar" | "floating" | "inset"
  collapsible?: "offcanvas" | "icon" | "none"
  dir?: "ltr" | "rtl"
}

const {
  class: className,
  side = "left",
  variant = "sidebar",
  collapsible = "offcanvas",
  dir,
  ...props
} = Astro.props
---

{
  collapsible === "none" ? (
    <div
      data-slot="sidebar"
      data-state="expanded"
      data-collapsible="none"
      data-variant={variant}
      data-side={side}
      data-sidebar-collapsible="none"
      dir={dir}
      class={cn(
        "bg-sidebar text-sidebar-foreground flex h-full w-(--sidebar-width) flex-col",
        className
      )}
      {...props}
    >
      <slot />
    </div>
  ) : (
    <>
      <Sheet data-sidebar="sheet" defaultOpen={false}>
        <SheetContent
          dir={dir}
          side={side}
          showCloseButton={false}
          data-sidebar="sidebar"
          data-slot="sidebar"
          data-mobile="true"
          style="--sidebar-width: var(--sidebar-width-mobile);"
          class={cn(
            "bg-sidebar text-sidebar-foreground w-(--sidebar-width) p-0 md:hidden",
            className
          )}
        >
          <SheetHeader class="sr-only">
            <SheetTitle>Sidebar</SheetTitle>
            <SheetDescription>Displays the mobile sidebar.</SheetDescription>
          </SheetHeader>
          <div class="flex h-full w-full flex-col">
            <slot />
          </div>
        </SheetContent>
      </Sheet>

      <div
        data-slot="sidebar"
        data-state="expanded"
        data-collapsible=""
        data-variant={variant}
        data-side={side}
        data-sidebar-collapsible={collapsible}
        dir={dir}
        class="group peer text-sidebar-foreground hidden md:block"
      >
        <div
          data-slot="sidebar-gap"
          class={cn(
            "relative w-(--sidebar-width) bg-transparent transition-[width] duration-200 ease-linear",
            "group-data-[collapsible=offcanvas]:w-0",
            "group-data-[side=right]:rotate-180",
            variant === "floating" || variant === "inset"
              ? "group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4)))]"
              : "group-data-[collapsible=icon]:w-(--sidebar-width-icon)"
          )}
        />
        <div
          data-slot="sidebar-container"
          data-side={side}
          dir={dir}
          class={cn(
            "fixed inset-y-0 z-10 hidden h-svh w-(--sidebar-width) transition-[left,right,width] duration-200 ease-linear data-[side=left]:left-0 data-[side=left]:group-data-[collapsible=offcanvas]:left-[calc(var(--sidebar-width)*-1)] data-[side=right]:right-0 data-[side=right]:group-data-[collapsible=offcanvas]:right-[calc(var(--sidebar-width)*-1)] md:flex",
            variant === "floating" || variant === "inset"
              ? "p-2 group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4))+2px)]"
              : "group-data-[collapsible=icon]:w-(--sidebar-width-icon) group-data-[side=left]:border-r group-data-[side=right]:border-l",
            className
          )}
          {...props}
        >
          <div
            data-sidebar="sidebar"
            data-slot="sidebar-inner"
            class="bg-sidebar group-data-[variant=floating]:ring-sidebar-border flex size-full flex-col group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:shadow-sm group-data-[variant=floating]:ring-1"
          >
            <slot />
          </div>
        </div>
      </div>
    </>
  )
}

