import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"button"> &
  HTMLAttributes<"a"> &
  HTMLAttributes<"div"> &
  HTMLAttributes<"span"> & {
    as?: "button" | "a" | "div" | "span"
    href?: string
  }

const {
  as: explicitTag,
  class: className,
  type,
