---
import type { HTMLAttributes } from "astro/types"
import type { TooltipAlign, TooltipSide } from "@data-slot/tooltip"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"

const variants = cva(
  "peer/menu-button group/menu-button flex w-full items-center gap-2 overflow-hidden rounded-md p-2 text-left text-sm ring-sidebar-ring outline-hidden transition-[width,height,padding] group-has-data-[sidebar=menu-action]/menu-item:pr-8 group-data-[collapsible=icon]:size-8! group-data-[collapsible=icon]:p-2! hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 active:bg-sidebar-accent active:text-sidebar-accent-foreground disabled:pointer-events-none disabled:opacity-50 aria-disabled:pointer-events-none aria-disabled:opacity-50 data-open:hover:bg-sidebar-accent data-open:hover:text-sidebar-accent-foreground data-active:bg-sidebar-accent data-active:font-medium data-active:text-sidebar-accent-foreground [&_svg]:size-4 [&_svg]:shrink-0 [&>span:last-child]:truncate",
  {
    variants: {
      variant: {
        default: "hover:bg-sidebar-accent hover:text-sidebar-accent-foreground",
        outline:
          "bg-background shadow-[0_0_0_1px_hsl(var(--sidebar-border))] hover:bg-sidebar-accent hover:text-sidebar-accent-foreground hover:shadow-[0_0_0_1px_hsl(var(--sidebar-accent))]",
      },
      size: {
        default: "h-8 text-sm",
        sm: "h-7 text-xs",
        lg: "h-12 text-sm group-data-[collapsible=icon]:p-0!",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

type TooltipValue =
  | string
  | (HTMLAttributes<"div"> & {
      content?: string
      children?: string
      side?: TooltipSide
      align?: TooltipAlign
      sideOffset?: number
      alignOffset?: number
      avoidCollisions?: boolean
      collisionPadding?: number
    })

type Props = VariantProps<typeof variants> &
  HTMLAttributes<"button"> &
  HTMLAttributes<"a"> &
  HTMLAttributes<"div"> &
  HTMLAttributes<"span"> & {
    as?: "a" | "button" | "div" | "span"
    href?: string
    isActive?: boolean
    active?: boolean
    tooltip?: TooltipValue
  }

const {
  as: explicitTag,
  class: className,
  variant = "default",
  size = "default",
  isActive,
  active = false,
  tooltip,
  type,
  ...props
} = Astro.props as Props

const Tag = explicitTag || ("href" in Astro.props ? "a" : "button")
const resolvedActive = isActive ?? active
const baseClassName = cn(variants({ variant, size }), className)
const resolvedTooltip =
  typeof tooltip === "string" ? { children: tooltip } : tooltip
const tooltipText =
  resolvedTooltip?.content ??
  (typeof resolvedTooltip?.children === "string"
    ? resolvedTooltip.children
    : undefined)
const {
  content: _tooltipContent,
  children: _tooltipChildren,
  ...tooltipProps
} = resolvedTooltip ?? {}
---

{
  tooltipText ? (
    <Tooltip>
      <TooltipTrigger
        as={Tag}
        data-slot="sidebar-menu-button"
        data-sidebar="menu-button"
        data-size={size}
        data-active={resolvedActive ? "true" : undefined}
        aria-current={resolvedActive ? "page" : undefined}
        type={Tag === "button" ? type || "button" : undefined}
        class={baseClassName}
        {...props}
      >
        <slot />
      </TooltipTrigger>
      <TooltipContent
        data-sidebar="menu-tooltip"
        side="right"
        align="center"
        hidden
        {...tooltipProps}
      >
        {tooltipText}
      </TooltipContent>
    </Tooltip>
  ) : (
    <Tag
      data-slot="sidebar-menu-button"
      data-sidebar="menu-button"
      data-size={size}
      data-active={resolvedActive ? "true" : undefined}
      aria-current={resolvedActive ? "page" : undefined}
      type={Tag === "button" ? type || "button" : undefined}
      class={baseClassName}
      {...props}
    >
      <slot />
    </Tag>
  )
}

